#!/usr/bin/env python
"""Simple test of the golden section search fix."""

import sys
import os
sys.path.insert(0, '.')

# Mock numpy for testing
class MockNp:
    def __init__(self):
        self.sqrt = lambda x: x**0.5
        self.log = lambda x: 0 if x <= 0 else 1  # Simplified
        self.trunc = lambda x: int(x)
        self.nanmax = lambda x: max([i for i in x if i == i]) if hasattr(x, '__iter__') else x
        self.where = lambda cond, x, y: x if cond else y
        self.zeros_like = lambda x: 0 if not hasattr(x, '__iter__') else [0]*len(x)
        self.any = lambda x: any(x) if hasattr(x, '__iter__') else bool(x)
        self.array = list
        self.errstate = lambda **kwargs: self
        def __enter__(self): return self
        def __exit__(self, *args): pass

# Mock the imports in tools.py
import builtins
real_import = builtins.__import__

def mock_import(name, *args, **kwargs):
    if name == 'numpy':
        return MockNp()
    elif name == 'pandas':
        class MockPd:
            class DataFrame:
                pass
        return MockPd()
    elif name == 'pytz':
        class MockPytz:
            pass
        return MockPytz()
    elif name == 'warnings':
        import warnings
        return warnings
    else:
        return real_import(name, *args, **kwargs)

builtins.__import__ = mock_import

# Now import tools
exec(open('./pvlib/tools.py').read())

# Test the logic
print("Testing the fix logic...")
print("When diff = 0, iter_calc should be 0")
print("When diff != 0, iter_calc should be calculated")
print("\nThe fix avoids division by zero by only calculating")
print("np.log(atol / diff) for diff != 0")

# Check the actual code
with open('./pvlib/tools.py', 'r') as f:
    lines = f.readlines()
    in_func = False
    for i, line in enumerate(lines):
        if 'def _golden_sect_DataFrame' in line:
            in_func = True
        if in_func and 'iterlimit = 1 + np.nanmax(iter_calc)' in line:
            print(f"\nFound fixed code at line {i+1}:")
            for j in range(max(0, i-10), min(len(lines), i+5)):
                print(f"{j+1}: {lines[j].rstrip()}")
            break

print("\nFix looks good!")
EOF"}

